const express = require('express');
const app = express();
app.use(express.json({ limit: '10mb' }));
const HTML = Buffer.from('', 'base64').toString('utf8');
app.get('/', (req, res) => { res.setHeader('Content-Type', 'text/html'); res.send(HTML); });
app.post('/api/claude', async (req, res) => {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) return res.status(503).json({ error: { message: 'ANTHROPIC_API_KEY not set in Render Environment.' } });
  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify(req.body)
    });
    const d = await r.json();
    res.status(r.status).json(d);
  } catch (e) { res.status(500).json({ error: { message: e.message } }); }
});
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log('CareRender on port ' + PORT));
